import{c as a,S as t,j as r,m as n}from"./chunks/framework.DvQr6YbT.js";const p=JSON.parse('{"title":"Sharing Knowledge","description":"","frontmatter":{},"headers":[],"relativePath":"sharing/index.md","filePath":"sharing/index.md","lastUpdated":1783418049000}'),o={name:"sharing/index.md"};function s(i,e,l,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="sharing-knowledge" tabindex="-1">Sharing Knowledge <a class="header-anchor" href="#sharing-knowledge" aria-label="Permalink to “Sharing Knowledge”">​</a></h1><p>Knowlery packages reviewed knowledge into <strong>bundles</strong> — sealed, versioned artifacts another vault can install. Sharing is a journey with distinct steps, and the most important thing to understand is that they are separate:</p><ol><li><strong>Export &amp; review</strong> — pick a seed topic; every page and source in scope gets an explicit per-item approval (nothing ships unreviewed). See the export command in the <a href="/reference/">Reference</a>.</li><li><strong><a href="./publish">Publish</a></strong> — <code>knowlery bundle publish</code> creates a GitHub Release in your configured repo and hands back the complete message to forward (URL, checksum, audience). Private by default; public destinations pass a second gate.</li><li><strong><a href="./grant-access">Grant access</a></strong> — publishing does <strong>not</strong> make the bundle reachable. Who can install depends on where it lives: public host (anyone), private repo (collaborators or org members), or a file you sent directly.</li><li><strong>Install</strong> — <a href="./install-from-url">from a URL</a> or from a local file.</li><li><strong><a href="./subscribe-update">Subscribe &amp; update</a></strong> — <code>check-updates</code> asks each bundle&#39;s source for newer versions; <code>update</code> installs them through the same gates. Pull-based, with local modifications protected.</li></ol><h2 id="the-recommended-team-setup-an-organization-shelf" tabindex="-1">The recommended team setup: an organization shelf <a class="header-anchor" href="#the-recommended-team-setup-an-organization-shelf" aria-label="Permalink to “The recommended team setup: an organization shelf”">​</a></h2><p>For a team, create one private repo under your GitHub organization — for example <code>your-org/kb-bundles</code> — and set the organization&#39;s base permission to <strong>Read</strong>.</p><ul><li>Every member can install from its release URLs, using their own GitHub login.</li><li>Access follows membership: joining the org grants it, leaving revokes it. No per-person, per-bundle management.</li><li>Anyone on the team can publish their bundles to the same shelf — it becomes the team&#39;s knowledge hub.</li></ul><p>GitHub&#39;s Free plan is sufficient (unlimited private repos and members). Finer scoping, if you need it, is a GitHub teams configuration — Knowlery never manages permissions itself.</p><h2 id="security-posture" tabindex="-1">Security posture <a class="header-anchor" href="#security-posture" aria-label="Permalink to “Security posture”">​</a></h2><ul><li>Bundles contain <strong>only what you approved item by item</strong> — never the vault wholesale.</li><li>Knowlery <strong>never stores or asks for tokens</strong>. Private sources are reached through your own <code>gh</code> CLI login or your browser session.</li><li>If a sharer gives you a checksum next to a link, verify the download: <code>knowlery bundle install &lt;url&gt; --verify &lt;sha256&gt;</code>.</li></ul>',9)])])}const g=a(o,[["render",s]]);export{p as __pageData,g as default};
